module RefModule(
	input wire clk,
	input wire clear,
	input wire en,
	input wire up_down,
	output reg [7:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (clear)
		Q <= 8'b00000000;
	else if (en) begin
		if (up_down)
			Q <= Q + 1;
		else
			Q <= Q - 1;
	end
end
endmodule
